/**
 * Message Display Observer
 * Hook: MessageDisplay (CC 2.1.208)
 *
 * Fires when assistant message text is displayed to the user. OBSERVER ONLY
 * (P3-A3): never blocks, never modifies — emits one compact telemetry line
 * (length + line-count metrics) so we learn the live payload shape and
 * display cadence.
 *
 * Input is UNTRUSTED and the payload shape is unverified against live CC.
 * Message CONTENT is never logged (assistant output can quote secrets,
 * tokens, or file contents) — only size metrics, and the scan itself is
 * capped so an oversized payload cannot burn the async budget.
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, logHook } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'notification/message-display-observer';

/** Only the first 64KB is scanned for line count — length is still exact. */
const MAX_SCAN_BYTES = 64 * 1024;

/** Read a string field off untrusted input; empty string when absent/non-string. */
function str(input: HookInput, key: string): string {
  const v = (input as unknown as Record<string, unknown>)[key];
  return typeof v === 'string' ? v : '';
}

/** Count newlines in a capped window of the text. */
function cappedLineCount(text: string): number {
  const window = text.length > MAX_SCAN_BYTES ? text.slice(0, MAX_SCAN_BYTES) : text;
  let lines = 1;
  for (let i = 0; i < window.length; i++) {
    if (window.charCodeAt(i) === 10) lines++;
  }
  return lines;
}

export async function messageDisplayObserver(
  input: HookInput,
  _ctx: HookContext = NOOP_CTX,
): Promise<HookResult> {
  try {
    // Candidate fields across plausible payload shapes — all optional.
    const text = str(input, 'message') || str(input, 'text') || str(input, 'content');

    logHook(
      HOOK_NAME,
      `message displayed len=${text.length} lines=${cappedLineCount(text)} truncated_scan=${text.length > MAX_SCAN_BYTES}`,
      'info',
    );
  } catch {
    // Observer only — never let telemetry failures surface to CC
  }
  return outputSilentSuccess();
}
